// @ts-check
'use strict';

const esbuild = require('esbuild');
const fs = require('fs');
const path = require('path');

async function build() {
  const distDir = path.join(__dirname, 'dist');
  if (!fs.existsSync(distDir)) fs.mkdirSync(distDir, { recursive: true });

  // Build the TypeScript bundle
  await esbuild.build({
    entryPoints: [path.join(__dirname, 'index.ts')],
    bundle: true,
    outfile: path.join(distDir, 'terminal.js'),
    format: 'iife',
    platform: 'browser',
    target: ['es2017'],
    minify: false,
    // isomorphic-git v1.37.5 exports field only exposes CJS (requires Node
    // 'crypto'). Override the main entry to ESM (uses globalThis.crypto).
    // Subpath imports like 'isomorphic-git/http/web' still resolve via exports.
    plugins: [{
      name: 'isomorphic-git-esm',
      setup(build) {
        const isoGitDir = path.dirname(require.resolve('isomorphic-git'));
        build.onResolve({ filter: /^isomorphic-git$/ }, () => ({
          path: path.join(isoGitDir, 'index.js'),
        }));
      },
    }],
    // Provide minimal node built-ins that isomorphic-git may reference
    define: {
      'process.env.NODE_ENV': JSON.stringify('production'),
    },
  });

  // Read the built JS
  const js = fs.readFileSync(path.join(distDir, 'terminal.js'), 'utf8');

  // Generate the HTML file with the JS inlined
  const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #0F172A; color: #E2E8F0; font-family: monospace; font-size: 13px; height: 100vh; display: flex; flex-direction: column; overflow: hidden; }
    #output { flex: 1; overflow-y: auto; padding: 12px; }
    .line { line-height: 20px; white-space: pre-wrap; word-break: break-all; }
    .command { color: #22C55E; }
    .error { color: #EF4444; }
    .info { color: #94A3B8; }
    #input-row { display: flex; align-items: center; padding: 8px 12px; border-top: 1px solid #1E293B; }
    #prompt { color: #22C55E; margin-right: 8px; }
    #input { flex: 1; background: transparent; border: none; outline: none; color: #E2E8F0; font-family: monospace; font-size: 13px; }
  </style>
</head>
<body>
  <div id="output"></div>
  <div id="input-row">
    <span id="prompt">$</span>
    <input id="input" type="text" autocomplete="off" autocorrect="off" autocapitalize="off" spellcheck="false" />
  </div>
  <script>${js}</script>
</body>
</html>`;

  fs.writeFileSync(path.join(distDir, 'terminal.html'), html, 'utf8');

  // Bundle size gate — fail build if over 2 MB (checked before writing .ts file)
  const htmlSize = Buffer.byteLength(html, 'utf8');
  if (htmlSize > 2 * 1024 * 1024) {
    console.warn(`⚠ WARNING: terminal.html is ${(htmlSize / 1024 / 1024).toFixed(2)} MB — exceeds 2 MB ceiling. Consider switching to asset-based loading.`);
    process.exit(1);
  } else {
    console.log(`✓ Bundle size: ${(htmlSize / 1024 / 1024).toFixed(2)} MB (within 2 MB ceiling)`);
  }

  // Write terminalHtmlContent.ts for import into React Native layer (only if size is OK)
  const tsContent = `// Auto-generated by build.js — do not edit manually.\nexport const TERMINAL_HTML = ${JSON.stringify(html)};\n`;
  fs.writeFileSync(path.join(__dirname, 'terminalHtmlContent.ts'), tsContent, 'utf8');
  console.log('✓ terminalHtmlContent.ts updated');

  const jsSize = fs.statSync(path.join(distDir, 'terminal.js')).size;
  console.log(
    `✓ terminal.html built successfully (${(htmlSize / 1024).toFixed(1)} KB, JS: ${(jsSize / 1024).toFixed(1)} KB)`,
  );
}

build().catch((err) => {
  console.error(err);
  process.exit(1);
});
